import{_ as o,c as t,o as i,ag as r}from"./chunks/framework.Bw-5EFTY.js";const g=JSON.parse('{"title":"DAG API Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/dag-api/docs/SPEC.md","filePath":"packages/dag-api/docs/SPEC.md"}'),c={name:"packages/dag-api/docs/SPEC.md"};function d(a,e,s,n,l,u){return i(),t("div",null,e[0]||(e[0]=[r('<h1 id="dag-api-specification" tabindex="-1">DAG API Specification <a class="header-anchor" href="#dag-api-specification" aria-label="Permalink to &quot;DAG API Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>API-layer composition for DAG design, runtime, diagnostics, and observability operations. Exposes endpoint-facing contracts, response shapes, and controller implementations that orchestrate domain services from <code>dag-core</code>, <code>dag-runtime</code>, <code>dag-projection</code>, and <code>dag-worker</code>.</p><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own core domain contracts (<code>IDagDefinition</code>, <code>IDagRun</code>, <code>ITaskRun</code>, state machines) -- those belong to <code>dag-core</code>.</li><li>Does not own runtime orchestration logic -- delegates to <code>dag-runtime</code> services.</li><li>Does not own worker execution or DLQ behavior -- delegates to <code>dag-worker</code>.</li><li>Does not own projection read-model logic -- delegates to <code>dag-projection</code>.</li><li>Depends on <code>dag-core</code> (SSOT), <code>dag-runtime</code>, <code>dag-projection</code>, and <code>dag-worker</code> as sibling dependencies.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package follows a controller-composition pattern:</p><ul><li><strong>Contracts</strong> (<code>contracts/</code>): Define API request/response types and the <code>IProblemDetails</code> error shape.</li><li><strong>Controllers</strong> (<code>controllers/</code>): Thin API controllers that delegate to domain services and map results to API responses. Four controllers: Design, Runtime, Diagnostics, Observability.</li><li><strong>Composition roots</strong> (<code>composition/</code>): Factory functions that wire domain services and controllers together from port dependencies. <ul><li><code>createDagControllerComposition</code> -- assembles all four controllers.</li><li><code>createDagExecutionComposition</code> -- assembles runtime + worker loop for in-process execution.</li><li><code>RunProgressEventBus</code> -- pub/sub bus for <code>TRunProgressEvent</code> streaming.</li></ul></li></ul><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><p>This package is SSOT for:</p><ul><li><code>IProblemDetails</code> -- RFC 7807-style error detail shape</li><li><code>TDesignApiSuccess&lt;TData&gt;</code>, <code>TDesignApiFailure</code>, <code>TDesignApiResponse&lt;TData&gt;</code> -- design API result aliases</li><li><code>IApiSuccess&lt;TData&gt;</code>, <code>IApiFailure&lt;TError&gt;</code>, <code>TApiResponse&lt;TData, TError&gt;</code> -- generic API envelope types</li><li><code>ICreateDefinitionRequest</code>, <code>IUpdateDraftRequest</code>, <code>IValidateDefinitionRequest</code>, <code>IPublishDefinitionRequest</code>, <code>IGetDefinitionRequest</code>, <code>IListDefinitionsRequest</code>, <code>IListNodeCatalogRequest</code> -- design API request types</li><li><code>IDefinitionListItem</code>, <code>IDefinitionValidationResult</code> -- design API response types</li><li><code>ITriggerRunRequest</code>, <code>IQueryRunRequest</code>, <code>ICancelRunRequest</code> -- runtime API request types</li><li><code>IAnalyzeFailureRequest</code>, <code>IRerunRequest</code>, <code>IReinjectDeadLetterRequest</code>, <code>IFailureCodeCount</code>, <code>IFailureAnalysis</code> -- diagnostics API types</li><li><code>IQueryRunProjectionRequest</code>, <code>IQueryLineageProjectionRequest</code>, <code>IObservabilityDashboardData</code> -- observability API types</li><li><code>IDagControllerComposition</code>, <code>IDagControllerCompositionDependencies</code>, <code>IDagControllerCompositionOptions</code> -- controller composition types</li><li><code>IDagExecutionComposition</code>, <code>IDagExecutionCompositionDependencies</code>, <code>IDagExecutionCompositionOptions</code> -- execution composition types</li><li><code>IRunProgressEventBus</code>, <code>TRunProgressEventListener</code> -- event bus types</li><li><code>INodeCatalogService</code> -- node catalog port interface</li><li><code>IDiagnosticsPolicy</code> -- diagnostics policy interface</li></ul><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><ul><li><code>toProblemDetails(error, instance, correlationId?)</code> -- maps <code>IDagError</code> to <code>IProblemDetails</code></li><li><code>toRuntimeProblemDetails(error, instance, correlationId?)</code> -- runtime-specific alias</li><li><code>DagDesignController</code> -- CRUD + validate + publish for DAG definitions</li><li><code>DagRuntimeController</code> -- trigger, query, cancel runs</li><li><code>DagObservabilityController</code> -- run/lineage/dashboard projection queries</li><li><code>DagDiagnosticsController</code> -- failure analysis, rerun, DLQ reinject</li><li><code>createDagControllerComposition(deps, options?)</code> -- wires all controllers</li><li><code>createDagExecutionComposition(deps, options)</code> -- wires runtime + worker loop</li><li><code>RunProgressEventBus</code> -- in-memory pub/sub for run progress events</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><code>INodeCatalogService</code> -- implement to provide node manifest listing and type validation.</li><li><code>IDiagnosticsPolicy</code> -- configure to enable/disable DLQ reinject.</li><li>All composition factories accept port interfaces (<code>IStoragePort</code>, <code>IQueuePort</code>, <code>IClockPort</code>, <code>ILeasePort</code>, <code>ITaskExecutorPort</code>) from <code>dag-core</code>, allowing custom implementations.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><p>All API errors use the <code>IProblemDetails</code> shape with URN-based <code>type</code> field:</p><ul><li><code>urn:robota:problems:dag:validation</code> (HTTP 400) -- validation failures</li><li><code>urn:robota:problems:dag:state_transition</code> (HTTP 409) -- invalid state transitions</li><li><code>urn:robota:problems:dag:lease</code> (HTTP 400) -- lease contract violations</li><li><code>urn:robota:problems:dag:dispatch</code> (HTTP 503) -- dispatch unavailability</li><li><code>urn:robota:problems:dag:task_execution</code> (HTTP 500) -- task execution failures</li></ul><p>Controller-specific codes:</p><ul><li><code>DAG_VALIDATION_DEFINITION_NOT_FOUND</code> (404)</li><li><code>DAG_VALIDATION_NODE_TYPE_NOT_REGISTERED</code> (400)</li><li><code>DAG_VALIDATION_NODE_CATALOG_NOT_CONFIGURED</code> (400)</li><li><code>DAG_POLICY_REINJECT_DISABLED</code> (409)</li></ul><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Interface</th><th>Implementor</th><th>Kind</th><th>Location</th></tr></thead><tbody><tr><td><code>IRunProgressEventBus</code></td><td><code>RunProgressEventBus</code></td><td>production</td><td><code>src/composition/run-progress-event-bus.ts</code></td></tr><tr><td><code>INodeCatalogService</code></td><td>(external: <code>BundledNodeCatalogService</code> in dag-server-core)</td><td>port</td><td>N/A (consumed via DI)</td></tr><tr><td><code>IDiagnosticsPolicy</code></td><td>(external)</td><td>port</td><td>N/A (consumed via DI)</td></tr></tbody></table><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><p>None. Controller and composition classes are standalone.</p><h3 id="port-consumption-via-di" tabindex="-1">Port Consumption via DI <a class="header-anchor" href="#port-consumption-via-di" aria-label="Permalink to &quot;Port Consumption via DI&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service/Controller</th><th>Injected Port (from dag-core)</th><th>Location</th></tr></thead><tbody><tr><td><code>createDagControllerComposition</code></td><td><code>IStoragePort</code>, <code>IQueuePort</code>, <code>IClockPort</code>, <code>ILeasePort</code>, <code>ITaskExecutorPort</code></td><td><code>src/composition/</code></td></tr><tr><td><code>createDagExecutionComposition</code></td><td><code>IStoragePort</code>, <code>IQueuePort</code>, <code>IClockPort</code>, <code>ILeasePort</code>, <code>ITaskExecutorPort</code></td><td><code>src/composition/</code></td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Consumer</th><th>Location</th></tr></thead><tbody><tr><td><code>IStoragePort</code> (dag-core)</td><td>Controller composition factories</td><td><code>src/composition/</code></td></tr><tr><td><code>IQueuePort</code> (dag-core)</td><td>Controller composition factories</td><td><code>src/composition/</code></td></tr><tr><td><code>IClockPort</code> (dag-core)</td><td>Controller composition factories</td><td><code>src/composition/</code></td></tr><tr><td><code>ILeasePort</code> (dag-core)</td><td>Controller composition factories</td><td><code>src/composition/</code></td></tr><tr><td><code>ITaskExecutorPort</code> (dag-core)</td><td>Controller composition factories</td><td><code>src/composition/</code></td></tr><tr><td><code>RunOrchestratorService</code> (dag-runtime)</td><td><code>DagRuntimeController</code></td><td><code>src/controllers/</code></td></tr><tr><td><code>ProjectionReadModelService</code> (dag-projection)</td><td><code>DagObservabilityController</code></td><td><code>src/controllers/</code></td></tr><tr><td><code>WorkerLoopService</code> (dag-worker)</td><td>Execution composition</td><td><code>src/composition/</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Unit tests</strong>: <code>src/__tests__/run-progress-event-bus.test.ts</code>, <code>execution-composition.test.ts</code></li><li><strong>E2E tests</strong>: <code>design-flow-e2e.test.ts</code>, <code>runtime-flow-e2e.test.ts</code>, <code>diagnostics-flow-e2e.test.ts</code>, <code>observability-flow-e2e.test.ts</code>, <code>single-dagrun-e2e.test.ts</code></li><li>Tests use in-memory port implementations from <code>dag-core</code>.</li><li>Coverage focus: controller request/response mapping, composition wiring, error-to-problem-details translation, event bus pub/sub lifecycle.</li><li>Run: <code>pnpm --filter @robota-sdk/dag-api test</code></li></ul>',31)]))}const m=o(c,[["render",d]]);export{g as __pageData,m as default};
